/* 文件头注释：动态规划解决组合数学问题 */
#include <bits/stdc++.h>
using namespace std;

const int MOD = 998244353;

// 快速幂函数，用于计算组合数
long long quick_pow(long long a, long long b) {
    long long res = 1;
    while (b) {
        if (b & 1) res = res * a % MOD;
        a = a * a % MOD;
        b >>= 1;
    }
    return res;
}

// 计算组合数C(n, k)
long long comb(int n, int k) {
    if (k > n) return 0;
    long long res = 1;
    for (int i = 1; i <= k; ++i) {
        res = res * (n - k + i) % MOD;
        res = res * quick_pow(i, MOD - 2) % MOD;
    }
    return res;
}

int main() {
    int T;
    cin >> T;
    while (T--) {
        int N, K;
        cin >> N >> K;

        // 计算每个剩余类的数量
        int r = N % MOD;
        int cnt = N / MOD;
        vector<long long> rem(MOD, cnt);
        for (int i = 1; i <= r; ++i) {
            rem[i]++;
        }

        // 动态规划数组，dp[i][j]表示选取i个数，和模MOD等于j的方案数
        vector<vector<long long>> dp(K + 1, vector<long long>(MOD, 0));
        dp[0][0] = 1; // 初始化，选取0个数，和为0的方案数为1

        for (int i = 1; i <= K; ++i) {
            for (int j = 0; j < MOD; ++j) {
                for (int k = 0; k < MOD; ++k) {
                    int new_j = (j + k) % MOD;
                    dp[i][new_j] = (dp[i][new_j] + dp[i - 1][j] * rem[k]) % MOD;
                }
            }
        }

        cout << dp[K][0] << endl;
    }
    return 0;
}
```

