        } else if (diffM >= diffY && diffM >= diffL) {
            result += 'M';
            M++;
            Y--;
            L--;
        } else {
            result += 'L';
            L++;
            Y--;
            M--;
        }

        // 检查是否有英雄的掌握程度低于0
        if (Y < 0 || M < 0 || L < 0) {
            cout << "-1" << endl;
            return 0;
        }

        steps++;
    }

    // 如果超过1000次操作仍未达到目标，输出-1
    cout << "-1" << endl;
    return 0;
}

