/* 文件头注释：核心算法为数学公式推导，关键技术为前缀和与模运算 */
#include <bits/stdc++.h>
using namespace std;

const int MOD = 998244353;

// 计算模逆元的函数
long long inv(long long a, long long mod) {
    long long res = 1;
    long long b = mod - 2;
    while (b > 0) {
        if (b & 1) res = (res * a) % mod;
        a = (a * a) % mod;
        b >>= 1;
    }
    return res;
}

int main() {
    int N;
    cin >> N;
    vector<int> x(N), y(N);
    long long sum_x = 0, sum_y = 0, sum_x2 = 0, sum_y2 = 0;

    for (int i = 0; i < N; ++i) {
        cin >> x[i] >> y[i];
        sum_x = (sum_x + x[i]) % MOD;
        sum_y = (sum_y + y[i]) % MOD;
        sum_x2 = (sum_x2 + 1LL * x[i] * x[i]) % MOD;
        sum_y2 = (sum_y2 + 1LL * y[i] * y[i]) % MOD;
    }

    // 重新推导公式：sum_{i,j} (x_i - x_j)^2 = N*sum(x_i^2) - (sum x_i)^2
    long long total_x = (1LL * N * sum_x2 - 1LL * sum_x * sum_x % MOD + MOD) % MOD;
    long long total_y = (1LL * N * sum_y2 - 1LL * sum_y * sum_y % MOD + MOD) % MOD;
    long long total = (total_x + total_y) % MOD;

    cout << total << endl;

    return 0;
}
```

