/* 文件头注释：动态规划解决组合数学问题 */
#include <bits/stdc++.h>
using namespace std;

const int MOD = 998244353;
const int G = 3; // 原根

// 快速幂函数，用于计算组合数
long long quick_pow(long long a, long long b) {
    long long res = 1;
    while (b) {
        if (b & 1) res = res * a % MOD;
        a = a * a % MOD;
        b >>= 1;
    }
    return res;
}

// 计算组合数C(n, k)
long long comb(int n, int k) {
    if (k > n) return 0;
    long long res = 1;
    for (int i = 1; i <= k; ++i) {
        res = res * (n - k + i) % MOD;
        res = res * quick_pow(i, MOD - 2) % MOD;
    }
    return res;
}

// 快速傅里叶变换
void ntt(vector<long long>& a, int inv) {
    int n = a.size();
    for (int i = 1, j = 0; i < n; ++i) {
        for (int k = n >> 1; (j ^= k) < k; k >>= 1);
        if (i < j) swap(a[i], a[j]);
    }
    for (int len = 2; len <= n; len <<= 1) {
        long long wn = quick_pow(G, (MOD - 1) / len);
        if (inv == -1) wn = quick_pow(wn, MOD - 2);
        for (int i = 0; i < n; i += len) {
            long long w = 1;
            for (int j = 0; j < len / 2; ++j) {
                long long u = a[i + j], v = a[i + j + len / 2] * w % MOD;
                a[i + j] = (u + v) % MOD;
                a[i + j + len / 2] = (u - v + MOD) % MOD;
                w = w * wn % MOD;
            }
        }
    }
    if (inv == -1) {
        long long inv_n = quick_pow(n, MOD - 2);
        for (int i = 0; i < n; ++i) a[i] = a[i] * inv_n % MOD;
    }
}

int main() {
    int T;
    cin >> T;
    while (T--) {
        int N, K;
        cin >> N >> K;

        if (N % MOD == 0) {
            // 特判：当N是MOD的倍数时，所有数模MOD的余数均匀分布
            cout << comb(N, K) << endl;
            continue;
        }

        // 计算每个剩余类的数量
        int r = N % MOD;
        int cnt = N / MOD;
        vector<long long> rem(MOD, cnt);
        for (int i = 1; i <= r; ++i) {
            rem[i]++;
        }

        // 初始化dp数组
        vector<long long> dp(MOD, 0);
        dp[0] = 1;

        // 使用FFT优化卷积
        int n = 1;
        while (n < 2 * MOD) n <<= 1;
        vector<long long> a(n), b(n);
        for (int i = 0; i < MOD; ++i) a[i] = dp[i];
        for (int i = 0; i < MOD; ++i) b[i] = rem[i];

        ntt(a, 1);
        ntt(b, 1);
        for (int i = 0; i < n; ++i) a[i] = a[i] * b[i] % MOD;
        ntt(a, -1);

        for (int i = 0; i < MOD; ++i) dp[i] = a[i];

        // 重复K-1次卷积
        for (int i = 1; i < K; ++i) {
            fill(a.begin(), a.end(), 0);
            fill(b.begin(), b.end(), 0);
            for (int j = 0; j < MOD; ++j) a[j] = dp[j];
