            ntt(a, 1);
            ntt(b, 1);
            for (int j = 0; j < n; ++j) a[j] = a[j] * b[j] % MOD;
            ntt(a, -1);

            for (int j = 0; j < MOD; ++j) dp[j] = a[j];
        }

        cout << dp[0] << endl;
    }
