bool canComplete(int m, const vector<int>& a, int K) {
    priority_queue<int, vector<int>, greater<int>> chefs; // 最小堆
    for (int i = 0; i < m; ++i) {
        chefs.push(0);
    }
    for (int time : a) {
        int earliest = chefs.top();
        chefs.pop();
        if (earliest + time > K) {
            return false;
        }
        chefs.push(earliest + time);
    }
    return true;
}
