        } else {
            cin >> u >> v;
            int pu = find(u);
            int pv = find(v);
            // 检查u和v是否在同一个连通分量中，并且该连通分量中没有被雪覆盖的顶点
            if (pu == pv && !hasCovered[pu]) {
                cout << "Yes\n";
            } else {
                cout << "No\n";
            }
        }
    }

