/* 文件头注释：使用并查集维护图的连通性，动态处理顶点被雪覆盖的情况 */
#include <bits/stdc++.h>
using namespace std;

const int MAXN = 2e5 + 5;

int parent[MAXN];
bool isCovered[MAXN]; // 记录顶点是否被雪覆盖
bool hasCovered[MAXN]; // 记录连通分量中是否包含被雪覆盖的顶点

