int find(int u) {
    if (parent[u] != u) {
        parent[u] = find(parent[u]);
    }
    return parent[u];
}

// 并查集的合并操作
void unite(int u, int v) {
    int pu = find(u);
    int pv = find(v);
    if (pu != pv) {
        parent[pu] = pv;
        hasCovered[pv] = hasCovered[pv] || hasCovered[pu]; // 合并时更新hasCovered状态
    }
}

int main() {
