                    // 如果连通分量中包含被雪覆盖的顶点，则u和v都必须未被雪覆盖
                    if (!isCovered[u] && !isCovered[v]) {
                        cout << "Yes\n";
                    } else {
                        cout << "No\n";
                    }
                } else {
                    // 如果连通分量中不包含被雪覆盖的顶点，则可以直接到达
                    cout << "Yes\n";
                }
            } else {
                // 如果u和v不在同一个连通分量中，则无法到达
                cout << "No\n";
            }
        }
    }

    return 0;
}
